// src/App.js
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import ProjectHub from './ProjectHub';
import FinanceDashboard from './FinanceDashboard';
import BudgetingTool from './BudgetingTool';
import RealEstate from './RealEstate';
import Documents from './Documents';
import Login from './Login';
import Splash from './Splash';
import Register from './Register';
import UpdatesHelp from './UpdatesHelp';
import RealEstateLookup from './RealEstateLookup';
import ThemeToggle from './ThemeToggle';
import ProtectedRoute from './ProtectedRoute';
import NavigationBar from './NavigationBar';
import FloatingPaths from './FloatingPaths';

function App() {
  const [darkMode, setDarkMode] = useState(() => {
    return localStorage.getItem('darkMode') === 'true';
  });

  const [isAuthenticated, setIsAuthenticated] = useState(() => {
    return localStorage.getItem('user') !== null;
  });

  useEffect(() => {
    const html = document.querySelector('html');
    if (darkMode) {
      html.classList.add('dark');
    } else {
      html.classList.remove('dark');
    }
    localStorage.setItem('darkMode', darkMode);
  }, [darkMode]);

  const toggleDarkMode = () => {
    setDarkMode(!darkMode);
  };

  const handleLogin = (username, fullName) => {
    localStorage.setItem('user', username);
    if (fullName) {
      localStorage.setItem('fullName', fullName);
    }
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem('user');
    localStorage.removeItem('fullName');
    setIsAuthenticated(false);
  };

  return (
    <Router>
      <div className="min-h-screen bg-white text-black dark:bg-gray-900 dark:text-white transition duration-300">
        {/* Navigation - only shown when authenticated */}
        {isAuthenticated && <NavigationBar onLogout={handleLogout} />}

        {/* Theme toggle (always visible) */}
        <ThemeToggle darkMode={darkMode} toggleDarkMode={toggleDarkMode} />

        {/* Animated background lines - globally rendered */}
        <div className="fixed inset-0 pointer-events-none z-0">
          <FloatingPaths position={1} />
          <FloatingPaths position={-1} />
        </div>

        {/* Routes */}
        <Routes>
          <Route path="/" element={<Splash />} />
          <Route path="/login" element={<Login onLogin={handleLogin} />} />
          <Route path="/register" element={<Register />} />

          {/* Protected Routes */}
          <Route path="/hub" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <ProjectHub />
            </ProtectedRoute>
          } />
          <Route path="/finance" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <FinanceDashboard />
            </ProtectedRoute>
          } />
          <Route path="/budget" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <BudgetingTool />
            </ProtectedRoute>
          } />
          <Route path="/real-estate" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <RealEstate />
            </ProtectedRoute>
          } />
          <Route path="/documents" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <Documents />
            </ProtectedRoute>
          } />
          <Route path="/updates" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <UpdatesHelp />
            </ProtectedRoute>
          } />
          <Route path="/lookup" element={
            <ProtectedRoute isAuthenticated={isAuthenticated}>
              <RealEstateLookup />
            </ProtectedRoute>
          } />
          {/* Catch-all */}
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
